import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)"
];

const ROUTER_ABI = [
  "function getAmountsOut(uint256 amountIn, address[] calldata path) external view returns (uint256[] memory amounts)",
  "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external returns (uint256[] memory amounts)",
  "function swapExactETHForTokens(uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external payable returns (uint256[] memory amounts)",
  "function swapExactTokensForETH(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external returns (uint256[] memory amounts)",
  "function WETH() external view returns (address)"
];

const MAX_UINT256 = ethers.MaxUint256;

export class TokenSwapDApp {
  constructor({
    provider,
    routerAddress,
    account = null,
    slippageBps = 50,
    deadlineSeconds = 60 * 20
  }) {
    this.provider = provider;
    this.routerAddress = routerAddress;
    this.account = account;
    this.slippageBps = slippageBps;
    this.deadlineSeconds = deadlineSeconds;
    this.router = new ethers.Contract(routerAddress, ROUTER_ABI, provider);
  }

  async connectSigner(signer) {
    this.signer = signer;
    this.router = this.router.connect(signer);
    if (!this.account) {
      this.account = await signer.getAddress();
    }
    return this.account;
  }

  setAccount(account) {
    this.account = account;
  }

  setSlippageBps(slippageBps) {
    this.slippageBps = slippageBps;
  }

  setDeadlineSeconds(deadlineSeconds) {
    this.deadlineSeconds = deadlineSeconds;
  }

  getTokenContract(tokenAddress, withSigner = false) {
    return new ethers.Contract(
      tokenAddress,
      ERC20_ABI,
      withSigner && this.signer ? this.signer : this.provider
    );
  }

  async getTokenMetadata(tokenAddress) {
    const token = this.getTokenContract(tokenAddress);
    const [decimals, symbol] = await Promise.all([
      token.decimals(),
      token.symbol()
    ]);
    return { tokenAddress, decimals, symbol };
  }

  async getBalance(tokenAddress, account = this.account) {
    if (!account) throw new Error("Account not set");
    const token = this.getTokenContract(tokenAddress);
    return token.balanceOf(account);
  }

  async getAllowance(tokenAddress, spender = this.routerAddress, owner = this.account) {
    if (!owner) throw new Error("Owner account not set");
    const token = this.getTokenContract(tokenAddress);
    return token.allowance(owner, spender);
  }

  async ensureMaxApproval(tokenAddress, spender = this.routerAddress) {
    if (!this.signer) throw new Error("Signer not connected");
    if (!this.account) this.account = await this.signer.getAddress();

    const token = this.getTokenContract(tokenAddress, true);
    const currentAllowance = await token.allowance(this.account, spender);

    if (currentAllowance === MAX_UINT256) {
      return { approved: false, tx: null, allowance: currentAllowance };
    }

    const tx = await token.approve(spender, MAX_UINT256);
    const receipt = await tx.wait();

    return {
      approved: true,
      tx,
      receipt,
      allowance: MAX_UINT256
    };
  }

  async quote(amountIn, path) {
    return this.router.getAmountsOut(amountIn, path);
  }

  calculateAmountOutMin(expectedAmountOut, slippageBps = this.slippageBps) {
    const numerator = BigInt(10000 - slippageBps);
    return (BigInt(expectedAmountOut) * numerator) / 10000n;
  }

  getDeadline() {
    return Math.floor(Date.now() / 1000) + this.deadlineSeconds;
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    recipient = this.account,
    slippageBps = this.slippageBps
  }) {
    if (!this.signer) throw new Error("Signer not connected");
    if (!recipient) throw new Error("Recipient not set");

    const path = [tokenIn, tokenOut];
    const amountsOut = await this.quote(amountIn, path);
    const expectedAmountOut = amountsOut[amountsOut.length - 1];
    const amountOutMin = this.calculateAmountOutMin(expectedAmountOut, slippageBps);

    await this.ensureMaxApproval(tokenIn, this.routerAddress);

    const tx = await this.router.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      path,
      recipient,
      this.getDeadline()
    );
    const receipt = await tx.wait();

    return {
      tx,
      receipt,
      path,
      amountIn,
      expectedAmountOut,
      amountOutMin
    };
  }

  async swapExactETHForTokens({
    tokenOut,
    amountInWei,
    recipient = this.account,
    slippageBps = this.slippageBps
  }) {
    if (!this.signer) throw new Error("Signer not connected");
    if (!recipient) throw new Error("Recipient not set");

    const weth = await this.router.WETH();
    const path = [weth, tokenOut];
    const amountsOut = await this.quote(amountInWei, path);
    const expectedAmountOut = amountsOut[amountsOut.length - 1];
    const amountOutMin = this.calculateAmountOutMin(expectedAmountOut, slippageBps);

    const tx = await this.router.swapExactETHForTokens(
      amountOutMin,
      path,
      recipient,
      this.getDeadline(),
      { value: amountInWei }
    );
    const receipt = await tx.wait();

    return {
      tx,
      receipt,
      path,
      amountIn: amountInWei,
      expectedAmountOut,
      amountOutMin
    };
  }

  async swapExactTokensForETH({
    tokenIn,
    amountIn,
    recipient = this.account,
    slippageBps = this.slippageBps
  }) {
    if (!this.signer) throw new Error("Signer not connected");
    if (!recipient) throw new Error("Recipient not set");

    const weth = await this.router.WETH();
    const path = [tokenIn, weth];
    const amountsOut = await this.quote(amountIn, path);
    const expectedAmountOut = amountsOut[amountsOut.length - 1];
    const amountOutMin = this.calculateAmountOutMin(expectedAmountOut, slippageBps);

    await this.ensureMaxApproval(tokenIn, this.routerAddress);

    const tx = await this.router.swapExactTokensForETH(
      amountIn,
      amountOutMin,
      path,
      recipient,
      this.getDeadline()
    );
    const receipt = await tx.wait();

    return {
      tx,
      receipt,
      path,
      amountIn,
      expectedAmountOut,
      amountOutMin
    };
  }

  async parseTokenAmount(tokenAddress, amount) {
    const { decimals } = await this.getTokenMetadata(tokenAddress);
    return ethers.parseUnits(amount.toString(), decimals);
  }

  async formatTokenAmount(tokenAddress, amount) {
    const { decimals } = await this.getTokenMetadata(tokenAddress);
    return ethers.formatUnits(amount, decimals);
  }
}

export async function createBrowserDApp({
  routerAddress,
  slippageBps = 50,
  deadlineSeconds = 60 * 20
}) {
  if (!window.ethereum) {
    throw new Error("No injected wallet found");
  }

  const provider = new ethers.BrowserProvider(window.ethereum);
  await provider.send("eth_requestAccounts", []);
  const signer = await provider.getSigner();

  const dapp = new TokenSwapDApp({
    provider,
    routerAddress,
    slippageBps,
    deadlineSeconds
  });

  await dapp.connectSigner(signer);
  return dapp;
}

export async function exampleUsage() {
  const dapp = await createBrowserDApp({
    routerAddress: "0xYourRouterAddress"
  });

  const tokenIn = "0xTokenInAddress";
  const tokenOut = "0xTokenOutAddress";
  const humanAmountIn = "1.0";

  const amountIn = await dapp.parseTokenAmount(tokenIn, humanAmountIn);

  const approvalResult = await dapp.ensureMaxApproval(tokenIn);
  console.log("Approval:", approvalResult);

  const swapResult = await dapp.swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn
  });

  console.log("Swap:", swapResult);
}